cron-webhook.content:
{
  name: "automated-assistant",
  model: { provider: "openai", model: "gpt-4o" },
  channels: [{ type: "cli", enabled: true }],
  automation: [
    {
      name: "morning-briefing",
      trigger: { type: "cron", expression: "0 8 * * 1-5" },
      action: { type: "chat", message: "Give me my morning briefing", channel: "cli" },
    },
    {
      name: "github-pr-review",
      trigger: { type: "webhook", path: "/webhook/github", method: "POST" },
      action: { type: "skill", skill: "github-pr-review" },
    },
    {
      name: "weekly-review",
      trigger: { type: "cron", expression: "0 18 * * 5" },
      action: { type: "chat", message: "Summarize my accomplishments this week", channel: "cli" },
    },
  ],
  gateway: {
    webhook: {
      enabled: true,
      port: 8080,
    },
  },
}

full.content:
{
  name: "full-assistant",
  version: "1.0.0",
  model: {
    provider: "openai",
    model: "gpt-4o",
    temperature: 0.7,
    maxTokens: 4096,
    systemPrompt: "You are a helpful AI assistant.",
  },
  channels: [
    { type: "cli", enabled: true },
    {
      type: "telegram",
      enabled: true,
      config: {
        botToken: "${TELEGRAM_BOT_TOKEN}",
        allowedUsers: ["user1"],
      },
    },
    {
      type: "discord",
      enabled: true,
      config: {
        webhookUrl: "${DISCORD_WEBHOOK_URL}",
      },
    },
    {
      type: "slack",
      enabled: true,
      config: {
        botToken: "${SLACK_BOT_TOKEN}",
        appToken: "${SLACK_APP_TOKEN}",
      },
    },
    {
      type: "webchat",
      enabled: true,
      config: {
        port: 3000,
      },
    },
  ],
  agents: [
    {
      name: "work",
      workspace: "./workspaces/coder",
      channels: ["cli", "slack"],
      model: {
        provider: "openai",
        model: "gpt-4o",
      },
    },
    {
      name: "personal",
      workspace: "./workspaces/assistant",
      channels: ["telegram", "webchat"],
    },
  ],
  memory: {
    enabled: true,
    maxEntries: 1000,
    autoRecall: true,
  },
  skills: {
    autoInstall: false,
    directory: "./skills",
  },
  automation: [
    {
      name: "daily-summary",
      trigger: {
        type: "cron",
        expression: "0 9 * * *",
      },
      action: {
        type: "chat",
        message: "Create a daily summary of my tasks and schedule",
        channel: "telegram",
      },
    },
  ],
  gateway: {
    host: "127.0.0.1",
    port: 18789,
    websocket: true,
  },
}

