multi-agent.content:
{
  name: "multi-agent-system",
  model: {
    provider: "openai",
    model: "gpt-4o",
  },
  agents: [
    {
      name: "coder",
      workspace: "./workspaces/coder",
      channels: ["cli", "slack"],
      description: "Programming and development assistant",
      skills: ["github", "code-review", "debug"],
    },
    {
      name: "assistant",
      workspace: "./workspaces/assistant",
      channels: ["telegram", "webchat"],
      description: "Personal life assistant",
      skills: ["weather", "calendar", "reminder"],
    },
    {
      name: "creative",
      workspace: "./workspaces/basic",
      channels: ["discord"],
      description: "Creative writing and brainstorming",
    },
  ],
  routing: {
    rules: [
      {
        channel: "slack",
        agent: "coder",
      },
      {
        channel: "telegram",
        agent: "assistant",
      },
      {
        channel: "discord",
        agent: "creative",
      },
    ],
  },
}

multi-channel.content:
{
  name: "multi-channel-bot",
  model: {
    provider: "openai",
    model: "gpt-4o",
  },
  channels: [
    { type: "telegram", enabled: true, config: { botToken: "${TELEGRAM_BOT_TOKEN}" } },
    { type: "discord", enabled: true, config: { webhookUrl: "${DISCORD_WEBHOOK_URL}" } },
    { type: "slack", enabled: true, config: { botToken: "${SLACK_BOT_TOKEN}", appToken: "${SLACK_APP_TOKEN}" } },
    { type: "webchat", enabled: true, config: { port: 3000 } },
    { type: "line", enabled: true, config: { channelToken: "${LINE_TOKEN}", channelSecret: "${LINE_SECRET}" } },
    { type: "whatsapp", enabled: true, config: { phoneNumberId: "${WA_PHONE_ID}", accessToken: "${WA_TOKEN}" } },
  ],
}
